import React, { useRef } from "react";
import { getImage } from "../../utils/getImage";

export default function Lightbox({
  selected,
  isOpen,
  onClose,
  onNext,
  onPrev,
  isMobile,
  zoom,
  setZoom,
}) {
  const lightboxRef = useRef(null);

  if (!isOpen || !selected) return null;

  return (
    <div
      ref={lightboxRef}
      role="dialog"
      aria-modal="true"
      aria-label={`Vista ampliada de ${selected.titulo}`}
      tabIndex={-1}
      onClick={onClose}
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.95)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 999,
      }}
    >
      {/* CONTENEDOR */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          width: "100%",
          flex: 1,
          position: "relative",
        }}
      >
        {/* IZQ */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            onPrev();
          }}
          style={arrowStyle("left", isMobile)}
        >
          ‹
        </button>

        {/* IMG */}
        <img
          src={getImage(selected, "full")}
          alt={selected.titulo}
          onClick={(e) => e.stopPropagation()}
          onDoubleClick={(e) => {
            e.stopPropagation();
            setZoom((z) => !z);
          }}
          style={{
            maxWidth: isMobile ? "85%" : "75%",
            maxHeight: zoom ? "none" : "80vh",
            borderRadius: "12px",
            transform: zoom ? "scale(1.8)" : "scale(1)",
            transition: "transform 0.3s ease",
            cursor: zoom ? "zoom-out" : "zoom-in",
          }}
        />

        {/* DER */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            onNext();
          }}
          style={arrowStyle("right", isMobile)}
        >
          ›
        </button>
      </div>

      {/* FOOTER */}
      <div
        style={{
          width: "100%",
          padding: "16px",
          background: "rgba(0,0,0,0.8)",
          color: "#fff",
          textAlign: "center",
        }}
      >
        <h3 style={{ margin: 0 }}>{selected.titulo}</h3>
        <p style={{ margin: 0, opacity: 0.7 }}>{selected.descripcion}</p>
      </div>
    </div>
  );
}

function arrowStyle(side, isMobile) {
  return {
    position: "absolute",
    [side]: 0,
    top: isMobile ? "33%" : 0,
    bottom: isMobile ? "33%" : 0,
    width: isMobile ? "20%" : "15%",
    display: "flex",
    alignItems: "center",
    justifyContent: side === "left" ? "flex-start" : "flex-end",
    fontSize: "40px",
    color: "rgba(255,255,255,0.8)",
    background: "transparent",
    border: "none",
    cursor: "pointer",
  };
}
